 8→struct UserXP: Codable, Sendable, Equatable {
 9→    var totalXP: Int
10→    var lastAwardDate: Date?
11→
12→    var level: Int { totalXP / 1000 + 1 }
13→    var currentLevelXP: Int { totalXP % 1000 }
14→    var xpToNextLevel: Int { 1000 - currentLevelXP }
15→    var levelProgress: Double { Double(currentLevelXP) / 1000.0 }
16→    var levelTitle: XPLevel { XPLevel(level: level) }
17→
18→    static let empty = UserXP(totalXP: 0)
19→}
