322→    private func checkProfileCompletion() async {
323→        guard let profileRepo = resolver.resolve(UserProfileRepository.self) else { return }
324→        do {
325→            if let profile = try await profileRepo.loadProfile() {
326→                isProfileIncomplete = !profile.isProfileComplete
