334→    private func checkGroupMembership() async {
335→        guard let authRepo = resolver.resolve(AuthenticationRepository.self) else {
336→            isInGroup = false
337→            return
338→        }
339→
340→        do {
341→            if let user = try await authRepo.currentUser() {
