349→    /// Loads the current workout entry for check-in
350→    private func loadCurrentEntry() {
351→        guard let planId = sessionStore.plan?.id,
352→              let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) else {
353→            return
354→        }
355→
356→        Task {
357→            do {
358→                let entries = try await historyRepo.listEntries(limit: 1, offset: 0)
359→                if let entry = entries.first, entry.planId == planId {
360→                    currentEntry = entry
361→                }
362→            } catch {
363→                #if DEBUG
364→                print("[WorkoutCompletion] Failed to load current entry: \(error)")
365→                #endif
366→            }
367→        }
368→    }
