370→    private func loadHealthKitAvailability() async {
371→        guard status == .completed else { return }
372→        
373→        guard
374→            let entitlementRepo = resolver.resolve(EntitlementRepository.self),
375→            let healthKit = resolver.resolve(HealthKitServicing.self)
376→        else {
377→            canUseHealthKit = false
378→            return
379→        }
380→        
381→        do {
382→            let entitlement = try await entitlementRepo.currentEntitlement()
383→            guard entitlement.isPro else {
384→                canUseHealthKit = false
385→                return
386→            }
387→            
388→            canUseHealthKit = true
389→            healthKitState = await healthKit.authorizationState()
390→        } catch {
391→            // Não bloquear o fluxo por HealthKit
392→            canUseHealthKit = false
393→        }
394→    }
