396→    private func exportToHealthKitIfPossible() async {
397→        guard status == .completed else { return }
398→        guard canUseHealthKit, healthKitState == .authorized else {
399→            healthKitExportMessage = "Conecte o Apple Health antes de exportar."
400→            return
401→        }
402→        guard let plan = sessionStore.plan else { return }
403→        guard
404→            let healthKit = resolver.resolve(HealthKitServicing.self),
405→            let historyRepo = resolver.resolve(WorkoutHistoryRepository.self)
406→        else { return }
407→        
408→        do {
409→            isExportingHealthKit = true
410→            defer { isExportingHealthKit = false }
411→            
412→            let receipt = try await healthKit.exportWorkout(plan: plan, completedAt: Date())
413→            
414→            // Vincular UUID ao último item do histórico com este planId (melhor esforço)
415→            let recent = try await historyRepo.listEntries(limit: 20, offset: 0)
416→            if let idx = recent.firstIndex(where: { $0.planId == plan.id }) {
417→                var updated = recent[idx]
418→                updated.healthKitWorkoutUUID = receipt.workoutUUID
419→                try await historyRepo.saveEntry(updated)
420→            }
421→            
422→            healthKitExportMessage = "Exportado para Apple Health."
423→        } catch {
424→            healthKitExportMessage = "Falha ao exportar para Apple Health: \(error.localizedDescription)"
425→        }
426→    }
