428→    private func awardXPIfNeeded() async {
429→        guard status == .completed else { return }
430→        guard let featureFlags = resolver.resolve(FeatureFlagChecking.self),
431→              await featureFlags.isFeatureEnabled(.gamificationEnabled) else { return }
432→        guard let awardUseCase = resolver.resolve(AwardXPUseCase.self) else { return }
433→
434→        // Get current streak for bonus calculation
435→        var currentStreak = 0
436→        if let statsRepo = resolver.resolve(UserStatsRepository.self),
437→           let stats = try? await statsRepo.getCurrentStats() {
438→            currentStreak = stats.currentStreak
439→        }
440→
441→        do {
442→            let result = try await awardUseCase.execute(type: .workoutCompleted, currentStreak: currentStreak)
443→            xpAwardResult = result
444→            if result.didLevelUp {
445→                showLevelUp = true
446→            }
447→        } catch {
448→            #if DEBUG
449→            print("[WorkoutCompletion] Failed to award XP: \(error)")
450→            #endif
451→        }
452→    }
453→
454→    private func generateNewWorkout() {
455→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
456→              let blocksRepo = resolver.resolve(WorkoutBlocksRepository.self),
457→              let composer = resolver.resolve(WorkoutPlanComposing.self) else {
458→            errorMessage = "Não foi possível carregar as configurações necessárias."
459→            return
460→        }
461→        
462→        isGeneratingNewPlan = true
463→        
464→        Task {
465→            do {
466→                // Busca o último checkIn usado (pode ser armazenado em UserDefaults ou no sessionStore)
467→                // Por enquanto, vamos usar o checkIn padrão baseado no perfil
468→                let profileUseCase = GetUserProfileUseCase(repository: profileRepo)
469→                guard let profile = try await profileUseCase.execute() else {
470→                    errorMessage = "Perfil não encontrado. Configure seu perfil primeiro."
471→                    isGeneratingNewPlan = false
472→                    return
473→                }
474→                
475→                // Gera um novo checkIn baseado no último foco usado (ou padrão)
476→                // Para simplificar, vamos usar o mesmo foco do plano atual
477→                let currentFocus = sessionStore.plan?.focus ?? .fullBody
478→                let checkIn = DailyCheckIn(
479→                    focus: currentFocus,
480→                    sorenessLevel: .none, // Novo treino sem considerar dor anterior
481→                    sorenessAreas: [],
482→                    energyLevel: 5
483→                )
484→                
485→                let generator = GenerateWorkoutPlanUseCase(
486→                    blocksRepository: blocksRepo,
487→                    composer: composer
488→                )
489→                let newPlan = try await generator.execute(profile: profile, checkIn: checkIn)
490→                
491→                await MainActor.run {
492→                    sessionStore.reset()
493→                    sessionStore.start(with: newPlan)
494→                    isGeneratingNewPlan = false
495→                    
496→                    // Navega para o novo treino
497→                    router.pop(on: .home) // summary
498→                    router.push(.workoutPlan(newPlan.id), on: .home)
499→                }
500→            } catch {
501→                await MainActor.run {
502→                    errorMessage = error.localizedDescription
503→                    isGeneratingNewPlan = false
504→                }
505→            }
506→        }
507→    }
508→
509→    private func finalizeFlow(goToHistory: Bool) {
510→        sessionStore.reset()
511→        router.pop(on: .home) // summary
512→        router.pop(on: .home) // detail
513→        router.pop(on: .home) // workout list
514→
515→        if goToHistory {
516→            router.select(tab: .activity)
517→        }
518→    }
