520→    private func saveRating(_ rating: WorkoutRating?) async {
521→        guard let planId = sessionStore.plan?.id else {
522→            hasRated = true
523→            return
524→        }
525→
526→        guard let historyRepo = resolver.resolve(WorkoutHistoryRepository.self) else {
527→            hasRated = true
528→            return
529→        }
530→
531→        isSavingRating = true
532→        defer { isSavingRating = false }
533→
534→        let useCase = SaveWorkoutRatingUseCase(historyRepository: historyRepo)
535→
536→        do {
537→            try await useCase.execute(rating: rating, planId: planId)
538→            hasRated = true
539→        } catch {
540→            // Still mark as rated to allow user to continue
541→            hasRated = true
542→            #if DEBUG
543→            print("[WorkoutCompletion] Failed to save rating: \(error)")
544→            #endif
545→        }
546→    }
