  1→//
  2→//  OptimizedPaywallView.swift
  3→//  FitToday
  4→//
  5→//  Paywall com assinaturas Pro e Elite (mensal/anual) via StoreKit 2.
  6→//
  7→
  8→import SwiftUI
  9→import StoreKit
 10→
 11→struct OptimizedPaywallView: View {
 12→    @Environment(\.dismiss) private var dismiss
 13→
 14→    @State private var storeService: StoreKitService
 15→    @State private var selectedTier: SubscriptionTier = .pro
 16→    @State private var selectedPeriod: SubscriptionPeriod = .annual
 17→    @State private var selectedProduct: Product?
 18→    @State private var errorMessage: ErrorMessage?
 19→
 20→    private let onPurchaseSuccess: () -> Void
 21→    private let onDismiss: () -> Void
 22→
 23→    enum SubscriptionPeriod: String, CaseIterable {
 24→        case monthly = "Mensal"
 25→        case annual = "Anual"
 26→    }
 27→
 28→    init(
 29→        storeService: StoreKitService,
 30→        onPurchaseSuccess: @escaping () -> Void = {},
 31→        onDismiss: @escaping () -> Void = {}
 32→    ) {
 33→        _storeService = State(initialValue: storeService)
 34→        self.onPurchaseSuccess = onPurchaseSuccess
 35→        self.onDismiss = onDismiss
 36→    }
 37→
 38→    var body: some View {
 39→        NavigationStack {
 40→            ScrollView {
 41→                VStack(spacing: FitTodaySpacing.lg) {
 42→                    PaywallHeroSection()
 43→
 44→                    periodToggle
 45→
 46→                    planCards
 47→
 48→                    featureList
 49→
 50→                    ctaSection
 51→
 52→                    legalFooter
 53→                }
 54→                .padding(.horizontal, FitTodaySpacing.md)
 55→                .padding(.bottom, FitTodaySpacing.xl)
 56→            }
 57→            .background(FitTodayColor.background.ignoresSafeArea())
 58→            .navigationBarTitleDisplayMode(.inline)
 59→            .toolbar {
 60→                ToolbarItem(placement: .cancellationAction) {
 61→                    Button {
 62→                        onDismiss()
 63→                        dismiss()
 64→                    } label: {
 65→                        Image(systemName: "xmark.circle.fill")
 66→                            .foregroundStyle(FitTodayColor.textSecondary)
 67→                    }
 68→                }
 69→            }
 70→            .task {
 71→                await storeService.loadProducts()
 72→                updateSelectedProduct()
 73→            }
 74→            .onChange(of: selectedTier) { _, _ in updateSelectedProduct() }
 75→            .onChange(of: selectedPeriod) { _, _ in updateSelectedProduct() }
 76→            .onChange(of: storeService.purchaseState) { _, newState in
 77→                if case .failed(let msg) = newState {
 78→                    errorMessage = ErrorMessage(title: "Erro", message: msg)
 79→                }
 80→            }
 81→            .errorToast(errorMessage: $errorMessage)
 82→        }
 83→    }
 84→
 85→    // MARK: - Period Toggle
 86→
 87→    private var periodToggle: some View {
 88→        HStack(spacing: 0) {
 89→            ForEach(SubscriptionPeriod.allCases, id: \.self) { period in
 90→                Button {
 91→                    withAnimation(.easeInOut(duration: 0.2)) {
 92→                        selectedPeriod = period
 93→                    }
 94→                } label: {
 95→                    HStack(spacing: FitTodaySpacing.xs) {
 96→                        Text(period.rawValue)
 97→                            .font(FitTodayFont.ui(size: 14, weight: .semiBold))
 98→                            .foregroundStyle(selectedPeriod == period ? .white : FitTodayColor.textSecondary)
 99→
100→                        if period == .annual {
101→                            Text("Economize 33%")
102→                                .font(FitTodayFont.ui(size: 10, weight: .bold))
103→                                .foregroundStyle(selectedPeriod == .annual ? FitTodayColor.brandAccent : FitTodayColor.textTertiary)
104→                                .padding(.horizontal, 5)
105→                                .padding(.vertical, 2)
106→                                .background(
107→                                    Capsule()
108→                                        .fill(selectedPeriod == .annual
109→                                              ? FitTodayColor.brandAccent.opacity(0.2)
110→                                              : Color.clear)
111→                                )
112→                        }
113→                    }
114→                    .frame(maxWidth: .infinity)
115→                    .padding(.vertical, FitTodaySpacing.sm)
116→                    .background(
117→                        RoundedRectangle(cornerRadius: FitTodayRadius.sm)
118→                            .fill(selectedPeriod == period ? FitTodayColor.brandPrimary : Color.clear)
119→                    )
120→                }
121→                .buttonStyle(.plain)
122→            }
123→        }
124→        .padding(4)
125→        .background(FitTodayColor.surface)
126→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
127→    }
128→
129→    // MARK: - Plan Cards
130→
131→    private var planCards: some View {
132→        HStack(spacing: FitTodaySpacing.sm) {
133→            planCard(for: .pro)
134→            planCard(for: .elite)
135→        }
136→    }
137→
138→    private func planCard(for tier: SubscriptionTier) -> some View {
139→        let isSelected = selectedTier == tier
140→        let product = productForCard(tier: tier)
141→
142→        return Button {
143→            withAnimation(.easeInOut(duration: 0.2)) {
144→                selectedTier = tier
145→            }
146→        } label: {
147→            VStack(spacing: FitTodaySpacing.sm) {
148→                // Tier badge
149→                HStack {
150→                    Image(systemName: tier == .elite ? "star.fill" : "crown.fill")
151→                        .font(.system(size: 12))
152→                    Text(tier.displayName)
153→                        .font(FitTodayFont.ui(size: 13, weight: .bold))
154→                }
155→                .foregroundStyle(isSelected ? .white : FitTodayColor.textPrimary)
156→                .padding(.horizontal, FitTodaySpacing.sm)
157→                .padding(.vertical, 6)
158→                .background(
159→                    Capsule()
160→                        .fill(isSelected ? tierColor(tier) : FitTodayColor.surfaceElevated)
161→                )
162→
163→                // Price
164→                if let product {
165→                    VStack(spacing: 2) {
166→                        Text(product.displayPrice)
167→                            .font(FitTodayFont.display(size: 22, weight: .extraBold))
168→                            .foregroundStyle(FitTodayColor.textPrimary)
169→                        Text(selectedPeriod == .annual ? "/ano" : "/mês")
170→                            .font(FitTodayFont.ui(size: 12, weight: .medium))
171→                            .foregroundStyle(FitTodayColor.textSecondary)
172→                        if selectedPeriod == .annual {
173→                            Text(monthlyEquivalent(for: product, tier: tier))
174→                                .font(FitTodayFont.ui(size: 11, weight: .medium))
175→                                .foregroundStyle(tierColor(tier))
176→                        }
177→                    }
178→                } else {
179→                    ProgressView()
180→                        .frame(height: 44)
181→                }
182→
183→                // Best value badge
184→                if tier == .elite {
185→                    Text("Melhor valor")
186→                        .font(FitTodayFont.ui(size: 10, weight: .bold))
187→                        .foregroundStyle(.white)
188→                        .padding(.horizontal, 8)
189→                        .padding(.vertical, 3)
190→                        .background(Capsule().fill(tierColor(.elite)))
191→                }
192→            }
193→            .frame(maxWidth: .infinity)
194→            .padding(FitTodaySpacing.md)
195→            .background(
196→                RoundedRectangle(cornerRadius: FitTodayRadius.md)
197→                    .fill(FitTodayColor.surface)
198→                    .overlay(
199→                        RoundedRectangle(cornerRadius: FitTodayRadius.md)
200→                            .stroke(
201→                                isSelected ? tierColor(tier) : FitTodayColor.outline.opacity(0.3),
202→                                lineWidth: isSelected ? 2 : 1
203→                            )
204→                    )
205→            )
206→            .fitGlowEffect(color: isSelected ? tierColor(tier).opacity(0.2) : .clear)
207→        }
208→        .buttonStyle(.plain)
209→        .animation(.easeInOut(duration: 0.2), value: isSelected)
210→    }
211→
212→    // MARK: - Feature List
213→
214→    private var featureList: some View {
215→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
216→            Text("O que está incluso")
217→                .font(FitTodayFont.ui(size: 15, weight: .bold))
218→                .foregroundStyle(FitTodayColor.textPrimary)
219→
220→            ForEach(features(for: selectedTier), id: \.title) { feature in
221→                featureRow(icon: feature.icon, title: feature.title, subtitle: feature.subtitle)
222→            }
223→        }
224→        .padding(FitTodaySpacing.md)
225→        .background(FitTodayColor.surface)
226→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
227→    }
228→
229→    private func featureRow(icon: String, title: String, subtitle: String?) -> some View {
230→        HStack(alignment: .top, spacing: FitTodaySpacing.sm) {
231→            Image(systemName: icon)
232→                .font(.system(size: 16))
233→                .foregroundStyle(tierColor(selectedTier))
234→                .frame(width: 24)
235→
236→            VStack(alignment: .leading, spacing: 2) {
237→                Text(title)
238→                    .font(FitTodayFont.ui(size: 14, weight: .semiBold))
239→                    .foregroundStyle(FitTodayColor.textPrimary)
240→                if let subtitle {
241→                    Text(subtitle)
242→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
243→                        .foregroundStyle(FitTodayColor.textSecondary)
244→                }
245→            }
246→
247→            Spacer()
248→
249→            Image(systemName: "checkmark.circle.fill")
250→                .font(.system(size: 16))
251→                .foregroundStyle(tierColor(selectedTier))
252→        }
253→    }
254→
255→    // MARK: - CTA Section
256→
257→    private var ctaSection: some View {
258→        VStack(spacing: FitTodaySpacing.md) {
259→            Button {
260→                Task { await purchaseSelectedProduct() }
261→            } label: {
262→                HStack(spacing: FitTodaySpacing.sm) {
263→                    if storeService.purchaseState == .purchasing {
264→                        ProgressView()
265→                            .progressViewStyle(CircularProgressViewStyle(tint: .white))
266→                    } else {
267→                        Text(ctaLabel)
268→                            .font(FitTodayFont.ui(size: 17, weight: .bold))
269→                    }
270→                }
271→                .frame(maxWidth: .infinity)
272→                .padding(.vertical, 16)
273→                .background(
274→                    LinearGradient(
275→                        colors: [tierColor(selectedTier), tierColor(selectedTier).opacity(0.75)],
276→                        startPoint: .leading,
277→                        endPoint: .trailing
278→                    )
279→                )
280→                .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
281→                .foregroundStyle(.white)
282→            }
283→            .disabled(selectedProduct == nil || storeService.purchaseState == .purchasing)
284→
285→            Button {
286→                Task { await restorePurchases() }
287→            } label: {
288→                HStack(spacing: FitTodaySpacing.xs) {
289→                    Image(systemName: "arrow.clockwise")
290→                    Text("Restaurar compras")
291→                }
292→                .font(FitTodayFont.ui(size: 14, weight: .medium))
293→                .foregroundStyle(FitTodayColor.brandPrimary)
294→            }
295→        }
296→    }
297→
298→    // MARK: - Legal Footer
299→
300→    private var legalFooter: some View {
301→        VStack(spacing: FitTodaySpacing.xs) {
302→            Text("A assinatura é renovada automaticamente. Cancele a qualquer momento nas configurações do dispositivo.")
303→                .font(FitTodayFont.ui(size: 11, weight: .medium))
304→                .foregroundStyle(FitTodayColor.textTertiary)
305→                .multilineTextAlignment(.center)
306→        }
307→        .padding(.horizontal, FitTodaySpacing.sm)
308→    }
309→
310→    // MARK: - Actions
311→
312→    private func purchaseSelectedProduct() async {
313→        guard let product = selectedProduct else { return }
314→        let success = await storeService.purchase(product)
315→        if success {
316→            onPurchaseSuccess()
317→            dismiss()
318→        }
319→    }
320→
321→    private func restorePurchases() async {
322→        let restored = await storeService.restorePurchases()
323→        if restored {
324→            onPurchaseSuccess()
325→            dismiss()
326→        } else if storeService.purchaseState != .failed("") {
327→            errorMessage = ErrorMessage(
328→                title: "Restaurar Compras",
329→                message: "Nenhuma assinatura ativa encontrada."
330→            )
331→        }
332→    }
333→
334→    // MARK: - Helpers
335→
336→    private func updateSelectedProduct() {
337→        let productID: String
338→        switch (selectedTier, selectedPeriod) {
339→        case (.pro, .monthly): productID = StoreKitProductID.proMonthly
340→        case (.pro, .annual): productID = StoreKitProductID.proAnnual
341→        case (.elite, .monthly): productID = StoreKitProductID.eliteMonthly
342→        case (.elite, .annual): productID = StoreKitProductID.eliteAnnual
343→        default: productID = StoreKitProductID.proAnnual
344→        }
345→        selectedProduct = storeService.product(id: productID)
346→    }
347→
348→    private func productForCard(tier: SubscriptionTier) -> Product? {
349→        let id = selectedPeriod == .annual
350→            ? (tier == .pro ? StoreKitProductID.proAnnual : StoreKitProductID.eliteAnnual)
351→            : (tier == .pro ? StoreKitProductID.proMonthly : StoreKitProductID.eliteMonthly)
352→        return storeService.product(id: id)
353→    }
354→
355→    private func monthlyEquivalent(for product: Product, tier: SubscriptionTier) -> String {
356→        // Annual price / 12 months — show as "R$X,XX/mês"
357→        guard let price = Double(product.price.description) else { return "" }
358→        let monthly = price / 12.0
359→        return String(format: "equivale a R$%.2f/mês", monthly).replacingOccurrences(of: ".", with: ",")
360→    }
361→
362→    private var ctaLabel: String {
363→        guard let product = selectedProduct else {
364→            return "Assinar \(selectedTier.displayName)"
365→        }
366→        return "Assinar \(selectedTier.displayName) — \(product.displayPrice)"
367→    }
368→
369→    private func tierColor(_ tier: SubscriptionTier) -> Color {
370→        tier == .elite ? FitTodayColor.brandAccent : FitTodayColor.brandPrimary
371→    }
372→
373→    private struct PaywallFeature {
374→        let icon: String
375→        let title: String
376→        let subtitle: String?
377→    }
378→
379→    private func features(for tier: SubscriptionTier) -> [PaywallFeature] {
380→        var list: [PaywallFeature] = [
381→            .init(icon: "chart.bar.fill", title: "Histórico completo de treinos", subtitle: nil),
382→            .init(icon: "bubble.left.and.bubble.right.fill", title: "FitOrb — Assistente IA", subtitle: tier == .pro ? "Chat IA ilimitado" : "Chat com contexto expandido"),
383→        ]
384→        if tier == .elite {
385→            list.append(.init(icon: "person.fill.checkmark", title: "Personal Trainer integrado", subtitle: "Acesso à rede de trainers"))
386→            list.append(.init(icon: "flame.fill", title: "Desafios ilimitados", subtitle: "Sem limite de grupos simultâneos"))
387→        }
388→        return list
389→    }
390→}
